use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()>{
    let file_paths = vec!["log1.txt", "log2.txt", "log3.txt"];
    let target_string = "ERROR: service X";
    let mut error_count = 0;

    for path in file_paths {
        println!("Processing {}", path);
        match File::open(path) {
            Ok(file) => {
                let reader = BufReader::new(file);
                for line in reader.lines() {
                    let line = line?;
                    if line.contains(target_string) {
                        error_count += 1;
                    }
                }
            }
            Err(e) => {
                println!("Could not open file {}: {}", path, e);
            }
        }
    }

    println!("nTotal occurrences of \"{}\": {}", target_string, error_count);
    Ok(())
}

