use std::fs::File;
use std::io::{self, Read};

struct SecurityKeyData {
    data: Vec<u8>,
}

impl SecurityKeyData {
    fn read_from_path(path: &str) -> io::Result<Self> {
        let mut file = File::open(path)?;
        let mut buffer = Vec::new();
        file.read_to_end(&mut buffer)?;
        Ok(SecurityKeyData { data: buffer })
    }

    fn display_summary(&self) {
        println!("Successfully read {} bytes of key material.", self.data.len());
    }
}

fn main() -> io::Result<()> {
    let dummy_path = "key_material.bin";

    // Create a dummy file for the example to run successfully
    use std::io::Write;
    let mut file = std::fs::File::create(dummy_path).unwrap();
    file.write_all(&[0xde, 0xad, 0xbe, 0xef]).unwrap();

    match SecurityKeyData::read_from_path(dummy_path) {
        Ok(key_data) => {
            key_data.display_summary();
        }
        Err(e) => {
            eprintln!("Failed to read key material: {}", e);
        }
    }

    std::fs::remove_file(dummy_path)?; 
    Ok(())
}

use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

struct BlogPost {
    slug: String,
    content: String,
}

fn read_blog_posts(directory: &Path) -> io::Result<Vec<BlogPost>> {
    let mut posts = Vec::new();
    if !directory.is_dir() {
        return Err(io::Error::new(io::ErrorKind::NotFound, "Directory not found"));
    }

    let entries = std::fs::read_dir(directory)?;

    for entry in entries {
        let entry = entry?;
        let path = entry.path();
        if path.extension().map_or(false, |ext| ext == "md") {
            let mut file = File::open(&path).expect("Failed to open file");
            let mut buffer = String::new();
            file.read_to_string(&mut buffer).expect("Failed to read content");

            if let Some(stem) = path.file_stem().unwrap().to_str() {
                posts.push(BlogPost {
                    slug: stem.to_string(),
                    content: buffer,
                });
            }
        }
    }
    Ok(posts)
}
